mapper.update:
/* 회의 상태/종료일시 수정 ai.meeting.updateMeetingStatus */
UPDATE TB_MEETING SET
    STATUS      = #{status}
    , END_DT    = NOW()
    , MODIFY_DT = NOW()
WHERE MEETING_ID = #{meetingId}

/* 회의 제목 수정 (AI 자동 생성 반영) ai.meeting.updateMeetingTitle */
UPDATE TB_MEETING SET
    MEETING_TITLE = #{meetingTitle}
    , MODIFY_DT = NOW()
WHERE MEETING_ID = #{meetingId}

/* 회의 삭제 (논리삭제) ai.meeting.deleteMeeting */
UPDATE TB_MEETING SET
    USE_YN      = 'N'
    , MODIFY_DT = NOW()
WHERE MEETING_ID = #{meetingId}

/* 회의록 수정 ai.meeting.updateMeetingMinutes */
UPDATE TB_MEETING_MINUTES SET
    FULL_TEXT       = #{fullText}
    , SUMMARY       = #{summary}
    , DECISIONS     = #{decisions}
    , TODO_LIST     = #{todoList}
    , MODIFY_DT     = NOW()
WHERE MINUTES_ID = #{minutesId}

/* 화자 매핑 (실명/사용자ID) 수정 ai.meeting.updateSpeakerMapping */
UPDATE TB_MEETING_SPEAKER SET
    SPEAKER_NM  = #{speakerNm}
    , USER_ID   = #{speakerUserId}
    , MODIFY_DT = NOW()
WHERE SPEAKER_ID = #{speakerId}

/* 오디오 처리 상태 수정 ai.meeting.updateMeetingAudioStatus */
UPDATE TB_MEETING_AUDIO SET
    STATUS      = #{audioStatus}
    , DURATION_SEC = #{durationSec}
    ,    ERROR_MSG    = #{errorMsg}
    , MODIFY_DT = NOW()
WHERE MEETING_ID = #{meetingId}
